import { signal, computed } from '@angular/core';

export function createStore<T>(initial: T) {
  const state = signal(initial);
  return {
    select: <K>(fn: (s: T) => K) => computed(() => fn(state())),
    patch: (partial: Partial<T>) =>
      state.update((s) => ({ ...s, ...partial })),
    snapshot: () => state(),
  };
}

